oxy_webhelp_navlinks = {"data_impact_investigation-d30753e44063":{"topics":[{"title":"Prerequisites and supported object types","shortdesc":"<p class=\"shortdesc\">Requirements for accessing data impact investigation and the workload types that         support the feature.<\/p>","href":"saas\/data_impact_prereq_object_types.html","attributes":{"data-id":"data_impact_prereq_object_types"},"menu":{"hasChildren":false},"tocID":"data_impact_prereq_object_types-d30753e44074","topics":[]},{"title":"Investigation dashboard","shortdesc":"<p class=\"shortdesc\">The Investigation dashboard lists all objects with <span class=\"ph\">Anomaly Detection<\/span> enabled and         their most recent file change activity, so administrators can quickly identify objects         impacted by a deletion or encryption event.<\/p>","href":"saas\/data_impact_investigation_dashboard.html","attributes":{"data-id":"data_impact_investigation_dashboard"},"menu":{"hasChildren":false},"tocID":"data_impact_investigation_dashboard-d30753e44085","topics":[]},{"title":"Individual object view","shortdesc":"<p class=\"shortdesc\">The individual object view shows file change activity for a single protected object         across backup snapshots. The Snapshot and File Activity tabs support investigation and recovery initiation at the         snapshot level and file level.<\/p>","href":"saas\/data_impact_individual_object_view.html","attributes":{"data-id":"data_impact_individual_object_view"},"menu":{"hasChildren":false},"tocID":"data_impact_individual_object_view-d30753e44099","topics":[]},{"title":"Investigating data impact","shortdesc":"<p class=\"shortdesc\">Identify objects affected by a deletion or encryption event, verify the scope of         impact using snapshot-level file change data, and initiate recovery to a healthy         point-in-time snapshot.<\/p>","href":"saas\/investigating_data_impact.html","attributes":{"data-id":"investigating_data_impact"},"menu":{"hasChildren":false},"tocID":"investigating_data_impact-d30753e44110","topics":[]},{"title":"Recovering impacted files and folders","shortdesc":"<p class=\"shortdesc\">Recover a specific set of files or folders impacted by a deletion or encryption         event, without recovering the entire object.<\/p>","href":"saas\/recovering_impacted_files.html","attributes":{"data-id":"recovering_impacted_files"},"menu":{"hasChildren":false},"tocID":"recovering_impacted_files-d30753e44121","topics":[]}]}};